module.exports = function(RED) {
    function OutputNode(config) {
        RED.nodes.createNode(this, config);
        const node = this;

        node.on("input", function(msg) {
            msg.payload = `Processed by output node: ${node.name || ""}`;
            node.send(msg);
        });
    }

    RED.nodes.registerType("output-node", OutputNode);
}